if pulse_idx >= len(companies):
    output = None
else:
    c = companies[pulse_idx]
    output = {
        'company_name': c.get('name', ''),
        'company_row': str(c.get('row', pulse_idx + 2)),
        'poc_name': c.get('poc_name', ''),
        'poc_email': c.get('poc_email', ''),
        'industry': c.get('industry', ''),
        'company_url': c.get('url', ''),
        'event_description': payload.get('event_description', ''),
        'sheet_id': payload.get('sheet_id', ''),
        'template': payload.get('template', '{}'),
        'llm_provider': payload.get('llm_provider', 'openrouter'),
        'llm_model': payload.get('llm_model', ''),
        'api_keys': payload.get('api_keys', '{}'),
        'google_credentials': payload.get('google_credentials', ''),
    }
"""
}

