synthesizer = ExecPython -> (response: String) {
  label: "Research Synthesizer LLM"
  code: """
import json, urllib.request, os

def pick_key(provider, keys_json, env):
    keys = json.loads(keys_json or '{}')
    order = [provider, 'openrouter', 'gemini', 'groq']
    for p in order:
        k = keys.get(p) or env.get(f'{p.upper()}_API_KEY') or env.get({'openrouter':'OPENROUTER_API_KEY','gemini':'GEMINI_API_KEY','groq':'GROQ_API_KEY'}[p])
        if k:
            return p, k
    raise RuntimeError('No LLM API key available')

def call_openrouter(model, key, prompt):
    req = urllib.request.Request('https://openrouter.ai/api/v1/chat/completions', data=json.dumps({
        'model': model, 'messages': [{'role':'user','content':prompt}], 'temperature': 0.3
    }).encode(), headers={'Authorization': f'Bearer {key}', 'Content-Type':'application/json'})
    with urllib.request.urlopen(req, timeout=120) as r:
        return json.loads(r.read())['choices'][0]['message']['content']

def call_gemini(model, key, prompt):
    url = f'https://generativelanguage.googleapis.com/v1beta/models/{model}:generateContent?key={key}'
    req = urllib.request.Request(url, data=json.dumps({'contents':[{'parts':[{'text':prompt}]}]}).encode(), headers={'Content-Type':'application/json'})
    with urllib.request.urlopen(req, timeout=120) as r:
        return json.loads(r.read())['candidates'][0]['content']['parts'][0]['text']

def call_groq(model, key, prompt):
    req = urllib.request.Request('https://api.groq.com/openai/v1/chat/completions', data=json.dumps({
        'model': model, 'messages': [{'role':'user','content':prompt}], 'temperature': 0.3
    }).encode(), headers={'Authorization': f'Bearer {key}', 'Content-Type':'application/json'})
    with urllib.request.urlopen(req, timeout=120) as r:
        return json.loads(r.read())['choices'][0]['message']['content']

provider = llm_provider
model = llm_model
p, key = pick_key(provider, api_keys, os.environ)
if p == 'openrouter':
    output = call_openrouter(model, key, prompt)
elif p == 'gemini':
    output = call_gemini(model, key, prompt)
else:
    output = call_groq(model, key, prompt)
"""
}
synthesizer.prompt = synth_prompt.output
synthesizer.llm_provider = parse_input.llm_provider
