sheet_write = ExecPython -> (result: String) {
  label: "Write to Google Sheet"
  code: """
import json, urllib.request, os, time, base64, hmac, hashlib

def b64url(data):
    return base64.urlsafe_b64encode(data).rstrip(b'=').decode()

def sa_token(creds_json):
    creds = json.loads(creds_json) if creds_json else json.loads(os.environ.get('GOOGLE_SERVICE_ACCOUNT_JSON', '{}'))
    if not creds.get('client_email'):
        return None
    header = b64url(json.dumps({'alg':'RS256','typ':'JWT'}).encode())
    now = int(time.time())
    claim = b64url(json.dumps({
        'iss': creds['client_email'], 'scope': 'https://www.googleapis.com/auth/spreadsheets',
        'aud': 'https://oauth2.googleapis.com/token', 'iat': now, 'exp': now + 3600
    }).encode())
    signing_input = f'{header}.{claim}'.encode()
    from cryptography.hazmat.primitives import hashes, serialization
    from cryptography.hazmat.primitives.asymmetric import padding
    key = serialization.load_pem_private_key(creds['private_key'].encode(), password=None)
    sig = b64url(key.sign(signing_input, padding.PKCS1v15(), hashes.SHA256()))
    jwt = f'{header}.{claim}.{sig}'
    req = urllib.request.Request('https://oauth2.googleapis.com/token', data=urllib.parse.urlencode({
        'grant_type': 'urn:ietf:params:oauth:grant-type:jwt-bearer', 'assertion': jwt
    }).encode(), headers={'Content-Type':'application/x-www-form-urlencoded'})
    with urllib.request.urlopen(req) as r:
        return json.loads(r.read())['access_token']

